def find_anagrams(s, p):
    if len(p) > len(s):
        return []
    p_count = [0] * 26
    s_count = [0] * 26
    for ch in p:
        p_count[ord(ch) - ord('a')] += 1
    result = []
    for i in range(len(s)):
        s_count[ord(s[i]) - ord('a')] += 1
        if i >= len(p):
            s_count[ord(s[i - len(p)]) - ord('a')] -= 1
        if i >= len(p) - 1 and s_count == p_count:
            result.append(i - len(p) + 1)
    return result
